class Playground {
    async run(inputs) {
        const inputStr = inputs[0] || '4, 9, 0, 5, 1';
        const vals = inputStr.split(',').map(v => {
            v = v.trim();
            return (v === 'null' || v === '') ? null : parseInt(v);
        });

        this.log('Initializing Tree...');
        this.tree.init(vals);
        this.pathNums.init([]);
        this.totalSum.init([0]);
        this.stack.init([]);
        await this.await();

        const root = this.tree.getRoot();
        if (!root) return;

        // Stack stores objects: { node, currentVal }
        // But our stack visualizer expects strings/numbers.
        // We'll manage a real stack 's' and visualize a simplified version.

        const s = [{ node: root, val: 0 }];
        this.stack.push(`(${root.val}, 0)`);
        this.log(`Push root ${root.val} to stack`);
        await this.await();

        let total = 0;

        while (s.length > 0) {
            const { node, val } = s.pop();
            this.stack.pop();

            // Calculate new value for this path
            const currentVal = val * 10 + node.val;
            this.log(`Visiting node ${node.val}. Path number so far: ${currentVal}`);
            this.tree.highlight(node.id, '#ec4899'); // Pink visiting
            await this.await();

            // Check if leaf
            if (!node.left && !node.right) {
                this.log(`Leaf found! Number: ${currentVal}`);
                this.tree.highlight(node.id, '#10b981'); // Green leaf

                this.pathNums.push(currentVal);
                total += currentVal;
                this.totalSum.set(0, total);
                await this.await();
            } else {
                // Create children value
                 if (node.right) {
                    this.log(`Push right child ${node.right.val}`);
                    s.push({ node: node.right, val: currentVal });
                    this.stack.push(`(${node.right.val}, ${currentVal})`);
                    this.tree.highlight(node.right.id, '#f59e0b');
                    await this.await();
                }
                if (node.left) {
                    this.log(`Push left child ${node.left.val}`);
                    s.push({ node: node.left, val: currentVal });
                    this.stack.push(`(${node.left.val}, ${currentVal})`);
                    this.tree.highlight(node.left.id, '#f59e0b');
                    await this.await();
                }
            }

            // Optional: reset color if not leaf?
            // this.tree.highlight(node.id, '#1e293b'); 
            // Let's keep the path highlighted or just clear marks occasionally?
            // For DFS, maybe we don't clear immediate visited nodes to show trace.
        }

        this.log(`Traversal Complete. Final Sum: ${total}`);
    }
}
